    pub fn parse_balance(&self, mut response: Value) -> Value {
        //
        // cashAccount
        //
        //    {
        //        "balances": {
        //            "eur": "0.0",
        //            "gbp": "0.0",
        //            "bch": "0.0",
        //            "xrp": "2.20188538338",
        //            "usd": "0.0",
        //            "eth": "0.0",
        //            "usdt": "0.0",
        //            "ltc": "0.0",
        //            "usdc": "0.0",
        //            "xbt": "0.0"
        //        },
        //        "type": "cashAccount"
        //    }
        //
        // marginAccount e,g, fi_xrpusd
        //
        //    {
        //        "auxiliary": {
        //            "usd": "0",
        //            "pv": "11.0",
        //            "pnl": "0.0",
        //            "af": "11.0",
        //            "funding": "0.0"
        //        },
        //        "marginRequirements": { im: '0.0', mm: '0.0', lt: '0.0', tt: "0.0" },
        //        "triggerEstimates": { im: '0', mm: '0', lt: "0", tt: "0" },
        //        "balances": { xrp: "11.0" },
        //        "currency": "xrp",
        //        "type": "marginAccount"
        //    }
        //
        // flex/multiCollateralMarginAccount
        //
        //    {
        //       "currencies": {
        //            "USDT": {
        //                "quantity": "1",
        //                "value": "1.0001",
        //                "collateral": "0.9477197625",
        //                "available": "1.0"
        //             }
        //       },
        //       "initialMargin": "0.0",
        //       "initialMarginWithOrders": "0.0",
        //       "maintenanceMargin": "0.0",
        //       "balanceValue": "1.0",
        //       "portfolioValue": "1.0",
        //       "collateralValue": "0.95",
        //       "pnl": "0.0",
        //       "unrealizedFunding": "0.0",
        //       "totalUnrealized": "0.0",
        //       "totalUnrealizedAsMargin": "0.0",
        //       "availableMargin": "0.95",
        //       "marginEquity": "0.95",
        //       "type": "multiCollateralMarginAccount"
        //    }
        //
        let mut accountType: Value = self.safe_string2(response.clone(), Value::Str("accountType".to_string()), Value::Str("type".to_string()), &[]);
        let mut isFlex: Value = Value::Bool(is_equal(&accountType, &Value::Str("multiCollateralMarginAccount".to_string())));
        let mut isCash: Value = Value::Bool(is_equal(&accountType, &Value::Str("cashAccount".to_string())));
        let mut balances: Value = self.safe_value2(response.clone(), Value::Str("balances".to_string()), Value::Str("currencies".to_string()), &[Value::Map({
            let mut m = indexmap::IndexMap::new();
            m
        })]);
        let mut result: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
            m
        });
        let mut currencyIds: Value = object_keys(&balances);
        {
                        let mut i: Value = Value::Int(0);
            let mut __for_first_858: bool = true;
            while { if !__for_first_858 { i = add(&i, &Value::Int(1)); } __for_first_858 = false; is_less_than(&i, &get_array_length(&currencyIds)) } {
            let mut currencyId: Value = get_value(&currencyIds, &i);
            let mut currencyId: Value = get_value(&currencyIds, &i);
            let mut balance: Value = get_value(&balances, &currencyId);
            let mut balance: Value = get_value(&balances, &currencyId);
            let mut code: Value = self.safe_currency_code(currencyId.clone(), &[]);
            let mut splitCode: Value = split(&code, &Value::Str("_".to_string()));
            let mut codeLength: Value = get_array_length(&splitCode);
            if is_greater_than(&codeLength, &Value::Int(1)) {
                continue;
            }
            let mut account: Value = self.account();
            if is_true(&isFlex) {
                add_element_to_object(&mut account, &Value::Str("total".to_string()), self.safe_string_k(balance.clone(), "quantity", &[]));
                add_element_to_object(&mut account, &Value::Str("free".to_string()), self.safe_string_k(balance.clone(), "available", &[]));
            }  else if is_true(&isCash) {
                add_element_to_object(&mut account, &Value::Str("used".to_string()), Value::Str("0.0".to_string()));
                add_element_to_object(&mut account, &Value::Str("total".to_string()), balance.clone());
            }  else {
                let mut auxiliary: Value = self.safe_value_k(response.clone(), "auxiliary", &[]);
                add_element_to_object(&mut account, &Value::Str("free".to_string()), self.safe_string_k(auxiliary.clone(), "af", &[]));
                add_element_to_object(&mut account, &Value::Str("total".to_string()), self.safe_string_k(auxiliary.clone(), "pv", &[]));
            }
            add_element_to_object(&mut result, &code, account.clone());
        }
        }
        return self.safe_balance(result.clone());

    Value::Null
}

